#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1010,INF=0x3f3f3f3f,Mod=998244353;
inline void DN(int &x){x>=Mod?x-=Mod:0;}inline void UP(int &x){x<0?x+=Mod:0;}
inline int qpow(int a,int b){int r(1);for(;b;b>>=1,a=1ll*a*a%Mod)if(b&1)r=1ll*r*a%Mod;return r;}
struct Itv{int l,r,w;}t[N];
int n,m,M,P[N],p,up[N],H[N],h,f0[N],f1[N],dp[N];
vector<int> dt[N],ed[N];int sm[N];
inline int DP(int w,vector<int>&dt,vector<int> &ed)
{
	if(!dt.size())return 0;
	sort(ed.begin(),ed.end(),[&](const int &x,const int &y){return t[x].r<t[y].r;});
	int mxl=0;for(int v:ed)mxl=max(mxl,t[v].l);int curl=0;unsigned el=0; 
	for(unsigned i=0;i<dt.size();++i)
	{
		int u=dt[i],L=P[u+1]-P[u],sum=0;
		
		UP(dp[i]=qpow(H[w],L)-qpow(H[w]-1,L));
		sm[i]=L;if(i)sm[i]+=sm[i-1];
		while(el<ed.size()&&t[ed[el]].r<=u){curl=max(curl,t[ed[el]].l);++el;}
		if(!curl)sum=qpow(H[w]-1,i?sm[i-1]:0);
		for(unsigned j=i-1;~j&&dt[j]>=curl;--j)sum=(1ll*dp[j]*qpow(H[w]-1,sm[i-1]-sm[j])+sum)%Mod;dp[i]=1ll*dp[i]*sum%Mod;
//		printf("QAQ %d :: %d %d %d\n",i,sum,curl,el);
	}
	int ans=0,g=1;for(unsigned i=dt.size()-1;~i&&dt[i]>=mxl;--i)
	{
		int u=dt[i];ans=(1ll*g*dp[i]+ans)%Mod;
		g=1ll*g*qpow(H[w]-1,P[u+1]-P[u])%Mod; 
	}
	return ans;
}
inline void Init()
{
	p=0;h=0;rep(1,1005,i)ed[i].clear(),dt[i].clear();
}
inline void Solve()
{
	n=read();m=read();M=read();Init();P[++p]=1;P[++p]=n+1;int ans=1;
	rep(1,m,i)P[++p]=t[i].l=read(),P[++p]=t[i].r=read()+1,H[++h]=t[i].w=read();;
	sort(P+1,P+p+1);n=unique(P+1,P+p+1)-P-1;sort(H+1,H+h+1);h=unique(H+1,H+h+1)-H-1;
	rep(1,m,i)t[i].l=lower_bound(P+1,P+n+1,t[i].l)-P,t[i].r=lower_bound(P+1,P+n+1,t[i].r)-P,t[i].w=lower_bound(H+1,H+h+1,t[i].w)-H;
	memset(up,0x3f,sizeof(up));rep(1,m,i){for(int j=t[i].l;j<t[i].r;++j)up[j]=min(up[j],t[i].w);}
	rep(1,m,i)ed[t[i].w].push_back(i);for(int i=1;i<n;++i)if(up[i]!=INF)dt[up[i]].push_back(i);else ans=1ll*ans*qpow(M,P[i+1]-P[i])%Mod;
//	rep(1,n,i)printf("%d ",up[i]);
//	printf("%d\n",ans);
	rep(1,h,i)ans=1ll*ans*DP(i,dt[i],ed[i])%Mod;printf("%d\n",ans);
}
int main()
{
	int T=read();while(T--)Solve();return 0;
}
